#nullable enable // autogenerated  

using System.Collections.Generic;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Enemies;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.netherReactorCore_Evoke)]
    public class NetherReactorCore_Evoke : ContraptionEvokeBehaviour
    {
        public NetherReactorCore_Evoke(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Evoke(Entity entity)
        {
            base.Evoke(entity);
            var column = entity.GetColumn();
            var lane = entity.GetLane();
            var spawnParams = entity.GetSpawnParams();
            var rng = entity.RNG;

            // 预先计算加权表（过滤掉权重为 0 的项）  
            var pool = BuildWeightedPool();

            for (int i = 0; i < gridOffsets.Length; i++)
            {
                var offset = gridOffsets[i];
                var enemyID = GetRandomWitherSkeleton(pool, rng);
                var position = entity.Level.GetEntityGridPosition(column + offset.x, lane + offset.y);
                entity.Spawn(enemyID, position, spawnParams);
            }
            Explosion.Spawn(entity, entity.GetCenter(), 120);
            entity.PlaySound(VanillaSoundID.explosion);
            entity.PlaySound(VanillaSoundID.witherSpawn);
            entity.Level.ShakeScreen(10, 0, 15);
        }

        // 构建 (id, 权重) 列表：白名单里没有在 weightOverrides 写权重的默认为 1，权重 0 不加入  
        private static List<(NamespaceID id, int weight)> BuildWeightedPool()
        {
            var pool = new List<(NamespaceID, int)>();
            foreach (var id in witherSkeletonWhitelist)
            {
                int weight = weightOverrides.TryGetValue(id, out var w) ? w : DEFAULT_WEIGHT;
                if (weight <= 0)
                    continue; // 权重为 0 永远不会被选到  
                pool.Add((id, weight));
            }
            return pool;
        }

        private static NamespaceID GetRandomWitherSkeleton(List<(NamespaceID id, int weight)> pool, RandomGenerator rng)
        {
            // 兜底：如果池子为空，返回一个默认敌人  
            if (pool.Count == 0)
                return VanillaEnemyID.WitherSkeleton;

            int total = 0;
            for (int i = 0; i < pool.Count; i++)
                total += pool[i].weight;

            int roll = rng.Next(total); // [0, total)  
            int acc = 0;
            for (int i = 0; i < pool.Count; i++)
            {
                acc += pool[i].weight;
                if (roll < acc)
                    return pool[i].id;
            }
            return pool[pool.Count - 1].id;
        }

        private static readonly Vector2Int[] gridOffsets = new Vector2Int[]
        {
            Vector2Int.right,
            Vector2Int.up,
            Vector2Int.left,
            Vector2Int.down
        };

        // mvz2:WitherSkeleton_Exp 分类下可被召唤的凋灵骷髅白名单  
        // 注意：请对照 VanillaEnemyID.cs 核对/补全成员名  
        private static readonly NamespaceID[] witherSkeletonWhitelist = new NamespaceID[]
        {
            VanillaEnemyID.WitherSkeleton,
            VanillaEnemyID.LeatherWitherSkeleton,
            VanillaEnemyID.IronWitherSkeleton,
            VanillaEnemyID.NetherCourier,
            VanillaEnemyID.WitherSkeletonHorse,
            VanillaEnemyID.WitherBoneWall,
            VanillaEnemyID.anubisand,
            VanillaEnemyID.berserker,
            VanillaEnemyID.BerserkerHead,
            VanillaEnemyID.NetherWarrior,
            VanillaEnemyID.NetherVanguard,
            VanillaEnemyID.NetherArcher,
            VanillaEnemyID.AssaultDullahan,
            VanillaEnemyID.Anubiskull,
            VanillaEnemyID.TeslaTrooper,
            VanillaEnemyID.mesmerizer,
            VanillaEnemyID.dullahan,
            VanillaEnemyID.hacker,
            VanillaEnemyID.netherHunter,
            VanillaEnemyID.netherMage,
        };

        // 加权表：没写的默认权重 DEFAULT_WEIGHT(=1)，权重 0 永远不选  
        // 例：想让 LeatherWitherSkeleton 概率更高，就给它写 10  
        private static readonly Dictionary<NamespaceID, int> weightOverrides = new Dictionary<NamespaceID, int>()
        {
            { VanillaEnemyID.WitherSkeleton, 4 },
            { VanillaEnemyID.LeatherWitherSkeleton, 6 },
            { VanillaEnemyID.IronWitherSkeleton, 3 },
            { VanillaEnemyID.NetherCourier, 2 },
            { VanillaEnemyID.WitherBoneWall, 6 },
            { VanillaEnemyID.BerserkerHead, 4 },
            { VanillaEnemyID.NetherWarrior, 2 },
            { VanillaEnemyID.dullahan, 3 },
            { VanillaEnemyID.netherHunter, 8 },
            { VanillaEnemyID.netherMage, 6 },
        };

        private const int DEFAULT_WEIGHT = 1;
    }
}
